#include <bits/stdc++.h>
#define ll long long
#define CI const int
#define PII pair<int,int>
#define mk(x,y) make_pair(x,y)
#define inf 0x3f3f3f3f
using namespace std;
inline int read()
{
	int x = 0, f = 1;
	char ch = getchar();
	while (ch < '0' || ch > '9')
	{
		if (ch == '-')f = -1;
		ch = getchar();
	}
	while (ch >= '0' && ch <= '9')x = x * 10 + ch - '0', ch = getchar();
	return x * f;
}
void write(int x)
{
	if (x < 0)putchar('-'), x = -x;
	if (x > 9)write(x / 10);
	putchar(x % 10 + '0');
	return;
}
CI MAXN = 5e5 + 5;
int t, n, m;
vector<int>e[MAXN];
int main()
{
	t = read();
	while (t--)
	{
		n = read();
		m = read();
		for (int i = 1; i <= n; ++i)e[i].clear();
		for (int i = 1, x, y; i <= m; ++i)
		{
			x = read();
			y = read();
			e[x].push_back(y);
		}
		for (int i = 1; i <= n; ++i)
		{
			sort(e[i].begin(), e[i].end());
			for (int j = 0; j < e[i].size(); ++j)
			{
				printf("%d ", e[i][j]);
			}
			puts("");
		}
	}
	return false;
}
